-- Drop any existing overloads of __mj."spCreateAIAgent" before recreating with new signature.
DO $$ DECLARE r record;
BEGIN
  FOR r IN
    SELECT oid::regprocedure AS sig FROM pg_proc
    WHERE proname = 'spCreateAIAgent' AND pronamespace = '__mj'::regnamespace
  LOOP
    EXECUTE 'DROP FUNCTION IF EXISTS ' || r.sig || ' CASCADE';
  END LOOP;
END $$;
