-- Drop any existing overloads of __mj."spCreateAIModelAction" before recreating with new signature.
DO $$ DECLARE r record;
BEGIN
  FOR r IN
    SELECT oid::regprocedure AS sig FROM pg_proc
    WHERE proname = 'spCreateAIModelAction' AND pronamespace = '__mj'::regnamespace
  LOOP
    EXECUTE 'DROP FUNCTION IF EXISTS ' || r.sig || ' CASCADE';
  END LOOP;
END $$;
CREATE OR REPLACE FUNCTION __mj."spCreateAIModelAction"(
    IN p_ID UUID DEFAULT NULL,
    IN p_AIModelID UUID DEFAULT NULL,
    IN p_AIActionID UUID DEFAULT NULL,
    IN p_IsActive BOOLEAN DEFAULT NULL
)
RETURNS SETOF __mj."vwAIModelActions" AS
$$
BEGIN
IF p_ID IS NOT NULL THEN
        -- User provided a value, use it
        INSERT INTO __mj."AIModelAction"
            (
                "ID",
                "AIModelID",
                "AIActionID",
                "IsActive"
            )
        VALUES
            (
                p_ID,
                p_AIModelID,
